def process(list, fieldName, ascending):
    """Sort list of structs/dicts by a field value"""
    if not list or not isinstance(list, (list, tuple)):
        return []
    field = str(fieldName or '')
    try:
        result = sorted(list, key=lambda x: x.get(field, 0) if isinstance(x, dict) else 0, reverse=not ascending)
        return result
    except:
        return list[:]
